#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2025/8/25# @Author : cyq# @File : requirements# @Software: PyCharm# @Desc:from fastapi import APIRouter, Dependsfrom app.controller import Authenticationfrom app.model.base import Userfrom app.response import Responsefrom app.schema.hub.requirementSchema import *from app.mapper.caseHub.requirementMapper import RequirementMapperfrom utils import logrouter = APIRouter(prefix="/hub/req", tags=['需求'])@router.post("/insertRequirement", description='添加需求信息')async def insert_requirement(req: AddRequirementsSchema, creator_user: User = Depends(Authentication())):    data = await RequirementMapper.insert_requirement(        user=creator_user,        **req.model_dump(exclude_none=True, exclude_unset=True)    )    return Response.success(data)@router.post("/updateRequirement", description='更新需求信息')async def update_requirement(req: UpdateRequirementsSchema, ur: User = Depends(Authentication())):    data = await RequirementMapper.update_by_id(        update_user=ur,        **req.model_dump(exclude_none=True)    )    return Response.success(data)@router.post("/removeRequirement", description='删除需求信息')async def remove_requirement(req: RemoveRequirementsSchema, _: User = Depends(Authentication())):    await RequirementMapper.delete_by_id(        req.requirement_id    )    return Response.success()@router.get("/getRequirement", description='获取需求信息')async def get_requirement(requirementId: int, _: User = Depends(Authentication())):    data = await RequirementMapper.get_requirement_info(        ident=requirementId    )    return Response.success(data)@router.post("/pageRequirement", description='分页需求信息')async def page_requirement(req: PageRequirementsSchema, _: User = Depends(Authentication())):    log.info(req)    data = await RequirementMapper.page_by_module(        **req.model_dump(exclude_none=True, exclude_unset=True)    )    return Response.success(data)@router.post("/updateRequirementCase", description="修改关联用例信息")async def update_requirement_case(req: UpdateRequirementCaseSchema, user: User = Depends(Authentication())):    await RequirementMapper.update_requirement_case(        user=user,        **req.model_dump(exclude_none=True, exclude_unset=True)    )    return Response.success()@router.post("/updateStatus", description="批量更新用例状态")async def batch_update_status(data: SetCasesStatusSchema, user: User = Depends(Authentication())):    """    批量更新多个用例的状态    :param data: 用例ID列表及目标状态    :param user: 认证用户    :return: 操作结果    """    await RequirementMapper.batch_update_status(user=user, **data.model_dump())    return Response.success()@router.post("/updateReview", description="批量更新用例评审")async def batch_update_status(data: SetCasesReviewSchema, user: User = Depends(Authentication())):    """    批量更新多个用例的状态    :param data: 用例ID列表及目标状态    :param user: 认证用户    :return: 操作结果    """    await RequirementMapper.update_cases_review(user=user, **data.model_dump())    return Response.success()